import xml.etree.ElementTree as ET

def validate_xml(xml_document):
    root = ET.fromstring(xml_document)
    if root.tag != "root":
        raise ValueError("Invalid root element")
    for child in root:
        if child.tag not in ["person", "phone"]:
            raise ValueError("Invalid child element")